import React, { useState } from "react";
import { 
  theme, 
  Typography, 
  Table, 
  Button, 
  Input, 
  Space, 
  Modal, 
  Form, 
  Select, 
  message 
} from "antd";
import { 
  PlusOutlined, 
  EditOutlined, 
  DeleteOutlined, 
  SearchOutlined, 
  FileExcelOutlined,
  ExclamationCircleOutlined,
  DeploymentUnitOutlined
} from "@ant-design/icons";
import { useI18n } from "@/framework/i18n/hooks";
import { mockSensors, PLANTS } from "../../dashboard/data/mockData";

const { Text, Title } = Typography;
const { useToken } = theme;
const { Option } = Select;

interface SensorData {
  key: string;
  id: string;
  name: string;
  type: string;
  value: string;
  status: string;
  plantId: number;
}

const initialData: SensorData[] = mockSensors.map(s => ({
  key: s.id.toString(),
  id: `SEN-${s.id.toString().padStart(3, '0')}`,
  name: s.name,
  type: s.name.includes("온도") ? "Temperature" : (s.name.includes("압력") ? "Pressure" : "General"),
  value: `${s.value}${s.unit || ""}`,
  status: "Active",
  plantId: s.plantId
}));

export default function SensorManagement() {
  const { token } = useToken();
  const { t } = useI18n(["settings"]);
  const [data, setData] = useState<SensorData[]>(initialData);
  const [selectedRowKeys, setSelectedRowKeys] = useState<React.Key[]>([]);
  const [isModalVisible, setIsModalVisible] = useState(false);
  const [editingItem, setEditingItem] = useState<SensorData | null>(null);
  const [form] = Form.useForm();

  const getAreaName = (plantId: number) => {
    return PLANTS.find(p => p.id === plantId)?.name || `Plant ${plantId}`;
  };

  const columns = [
    { title: t("sensor_management.columns.id", { ns: "settings" }), dataIndex: "id", key: "id", width: 120 },
    { title: t("sensor_management.columns.name", { ns: "settings" }), dataIndex: "name", key: "name", ellipsis: true },
    { title: t("sensor_management.columns.area", { ns: "settings" }), dataIndex: "plantId", key: "plantId", width: 220, 
      render: (id: number) => <Text style={{ color: token.colorPrimary, fontWeight: 600 }}>{getAreaName(id)}</Text>,
      sorter: (a: any, b: any) => getAreaName(a.plantId).localeCompare(getAreaName(b.plantId))
    },
    { title: t("sensor_management.columns.type", { ns: "settings" }), dataIndex: "type", key: "type", width: 140 },
    { title: t("sensor_management.columns.value", { ns: "settings" }), dataIndex: "value", key: "value", width: 120 },
    { title: t("sensor_management.columns.status", { ns: "settings" }), dataIndex: "status", key: "status", width: 100, align: "center" as const,
      render: (val: string) => <Text style={{ color: val === "Active" ? token.colorSuccess : (val === "Warning" ? token.colorWarning : token.colorError), fontWeight: 700 }}>{val}</Text> 
    },
  ];

  const handleAdd = () => {
    setEditingItem(null);
    form.resetFields();
    setIsModalVisible(true);
  };

  const handleEdit = () => {
    if (selectedRowKeys.length !== 1) {
      message.warning(t("area_management.messages.select_one_to_edit", { ns: "settings" }));
      return;
    }
    const target = data.find(it => it.key === selectedRowKeys[0]);
    if (target) {
      setEditingItem(target);
      form.setFieldsValue(target);
      setIsModalVisible(true);
    }
  };

  const handleDelete = () => {
    if (selectedRowKeys.length === 0) {
      message.warning(t("area_management.messages.select_to_delete", { ns: "settings" }));
      return;
    }
    Modal.confirm({
      title: t("area_management.messages.delete_confirm_title", { ns: "settings" }),
      icon: <ExclamationCircleOutlined />,
      content: t("area_management.messages.delete_confirm_content", { ns: "settings" }),
      onOk() {
        setData(data.filter(it => !selectedRowKeys.includes(it.key)));
        setSelectedRowKeys([]);
        message.success(t("area_management.messages.delete_success", { ns: "settings" }));
      },
    });
  };

  const handleSave = () => {
    form.validateFields().then(values => {
      if (editingItem) {
        setData(data.map(it => it.key === editingItem.key ? { ...it, ...values } : it));
        message.success(t("area_management.messages.save_success_edit", { ns: "settings" }));
      } else {
        const newItem = { ...values, key: Date.now().toString() };
        setData([...data, newItem]);
        message.success(t("area_management.messages.save_success_add", { ns: "settings" }));
      }
      setIsModalVisible(false);
    });
  };

  return (
    <div style={{ padding: "24px", background: token.colorBgLayout, minHeight: "100%" }}>
      <div style={{ marginBottom: 24, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <Title level={3} style={{ margin: 0 }}><DeploymentUnitOutlined /> {t("sensor_management.title", { ns: "settings" })}</Title>
        <Space size="middle">
          <Button icon={<PlusOutlined />} onClick={handleAdd}>{t("area_management.add", { ns: "settings" })}</Button>
          <Button icon={<EditOutlined />} onClick={handleEdit}>{t("area_management.edit", { ns: "settings" })}</Button>
          <Button danger icon={<DeleteOutlined />} onClick={handleDelete}>{t("area_management.delete", { ns: "settings" })}</Button>
          <Button icon={<FileExcelOutlined />}>{t("area_management.excel", { ns: "settings" })}</Button>
          <Input placeholder="Search" prefix={<SearchOutlined />} style={{ width: 200 }} />
        </Space>
      </div>

      <div style={{ background: token.colorBgContainer, padding: 16, borderRadius: token.borderRadiusLG, boxShadow: token.boxShadowTertiary, border: `1px solid ${token.colorBorderSecondary}` }}>
        <Table rowSelection={{ type: "checkbox", selectedRowKeys, onChange: (keys) => setSelectedRowKeys(keys) }} columns={columns} dataSource={data} pagination={{ pageSize: 12 }} scroll={{ y: "calc(100vh - 300px)" }} />
      </div>

      <Modal
        title={<div style={{ margin: "-16px -24px", padding: "16px 24px", background: token.colorPrimary, color: "white", borderRadius: `${token.borderRadiusLG}px ${token.borderRadiusLG}px 0 0`, fontSize: 18, fontWeight: 700 }}>{t("area_management.form.modal_title", { ns: "settings" })}</div>}
        open={isModalVisible}
        onOk={handleSave}
        onCancel={() => setIsModalVisible(false)}
        footer={[
          <Button key="cancel" onClick={() => setIsModalVisible(false)} style={{ height: 40, width: 80, borderRadius: token.borderRadius }}>{t("area_management.form.close", { ns: "settings" })}</Button>,
          <Button key="save" type="primary" onClick={handleSave} style={{ height: 40, width: 80, borderRadius: token.borderRadius }}>{t("area_management.form.save", { ns: "settings" })}</Button>,
        ]}
        centered
        width={550}
        closeIcon={<span style={{ color: "white" }}>X</span>}
      >
        <div style={{ paddingTop: 24 }}>
          <Form form={form} layout="vertical">
             <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16 }}>
                <Form.Item name="id" label={<Text strong>{t("sensor_management.columns.id", { ns: "settings" })}</Text>} rules={[{ required: true }]}>
                  <Input style={{ height: 40 }} />
                </Form.Item>
                <Form.Item name="name" label={<Text strong>{t("sensor_management.columns.name", { ns: "settings" })}</Text>} rules={[{ required: true }]}>
                  <Input style={{ height: 40 }} />
                </Form.Item>
             </div>
            
             <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16 }}>
                <Form.Item name="plantId" label={<Text strong>{t("sensor_management.columns.area", { ns: "settings" })}</Text>} rules={[{ required: true }]}>
                   <Select style={{ height: 40 }}>
                      {PLANTS.map(p => (
                        <Option key={p.id} value={p.id}>{p.name}</Option>
                      ))}
                   </Select>
                </Form.Item>
                <Form.Item name="type" label={<Text strong>{t("sensor_management.columns.type", { ns: "settings" })}</Text>}>
                  <Select style={{ height: 40 }}>
                    <Option value="Temperature">Temperature</Option>
                    <Option value="Pressure">Pressure</Option>
                    <Option value="Smoke">Smoke</Option>
                    <Option value="Motion">Motion</Option>
                  </Select>
                </Form.Item>
             </div>

             <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16 }}>
                <Form.Item name="value" label={<Text strong>{t("sensor_management.columns.value", { ns: "settings" })}</Text>}>
                  <Input style={{ height: 40 }} />
                </Form.Item>
                <Form.Item name="status" label={<Text strong>{t("sensor_management.columns.status", { ns: "settings" })}</Text>}>
                  <Select style={{ height: 40 }}>
                    <Option value="Active">Active</Option>
                    <Option value="Warning">Warning</Option>
                    <Option value="Inactive">Inactive</Option>
                  </Select>
                </Form.Item>
             </div>
          </Form>
        </div>
      </Modal>

      <style>{`
        .ant-table-thead > tr > th { background-color: ${token.colorFillAlter} !important; font-weight: 700 !important; }
        .ant-table-row:hover { cursor: pointer; }
      `}</style>
    </div>
  );
}
